      onTap: () {
        setState(() {
          showText = !showText;
        });
      },
      child: SizedBox.expand(
        child: Center(
          child: Container(
            width: 400,
            height: 400,
            color: Colors.red,
            child: text,
          ),
        ),
      ),
    );
  }
}
